import React, { useState } from 'react';
import axios from 'axios';
import { showToast } from '../Toasts';
import { Link } from 'react-router-dom';

const Register = () => {
  const [name, setName] = useState('');
  const [password, setPassword] = useState('');
  const [verifPassword, setVerifPassword] = useState('');
  const [errors, setErrors] = useState('');

  const gererSoumission = async (e) => {
    e.preventDefault();
    setErrors('');

    const response = await axios.post('http://localhost:4000/api/register', {
      name,
      password: password,
    });
    if (response.data.error) {
      showToast("error", response.data.error)
    } else {
      showToast("success", response.data.message)
    }
    console.log(response.data.user);
  };

  return (
    <div class="flex flex-col items-center">
      <h1 class="mt-[100px] text-6xl font-caesar">Inscription</h1>
      <form class="flex items-center w-full justify-center gap-12 mt-[60px] mb-[" onSubmit={gererSoumission}>
        <div class="flex flex-col gap-2 w-[30%]">
          <div class="flex flex-col items-center">
            <label>Prénom</label>
            <input
              class="rounded text-center w-full ring-1 ring-gray-300"
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Entrez votre prénom"
            />
          </div>
          <div class="flex flex-col items-center">
            <label>Mot de passe</label>
            <input
              class="rounded text-center w-full ring-1 ring-gray-300"
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Entrez votre mot de passe"
            />
          </div>
          <div class="flex flex-col items-center">
            <label>Confirmer mot de passe</label>
            <input
              class="rounded text-center w-full ring-1 ring-gray-300"
              type="password"
              value={verifPassword}
              onChange={(e) => setVerifPassword(e.target.value)}
              placeholder="Confirmer votre mot de passe"
            />
          </div>
          <button type="submit">S'inscrire</button>
        </div>
      </form>
      <div class="flex flex-col items-center justify-center">
        <p>Vous avez deja un compte ? </p>
        <Link class="underline" to='/login'>Cliquez ici</Link>
      </div>
    </div>
  );
};

export default Register;
